Get-Process POWERPNT,WINWORD,EXCEL -ErrorAction SilentlyContinue | Select-Object Name,Id,MainWindowTitle | Format-Table -AutoSize
"---attempt warm start---"
Get-Process POWERPNT -ErrorAction SilentlyContinue | Stop-Process -Force
Start-Sleep -Milliseconds 800
$proc = Start-Process "POWERPNT.EXE" -ArgumentList "/automation" -PassThru
Start-Sleep -Seconds 3
$pp = $null
for ($i=0; $i -lt 12 -and $pp -eq $null; $i++){
  try { $pp = [System.Runtime.InteropServices.Marshal]::GetActiveObject("PowerPoint.Application") } catch { Start-Sleep -Milliseconds 1000 }
}
if ($pp) { "ATTACHED via GetActiveObject; Version=" + $pp.Version } else { "FAILED to attach; proc.HasExited=" + $proc.HasExited }

Get-Process POWERPNT -ErrorAction SilentlyContinue | Stop-Process -Force
Start-Sleep -Milliseconds 700
# preemptively clear resiliency so the next COM launch isn't blocked by a recovery prompt
"StartupItems","DocumentRecovery" | ForEach-Object {
  $k = "HKCU:\Software\Microsoft\Office\16.0\PowerPoint\Resiliency\$_"
  if(Test-Path $k){ Remove-Item $k -Recurse -Force }
}
Start-Sleep -Milliseconds 400
Get-Content "C:\Users\namma\.claude\plm_slide_work\build_agenda_v15.ps1" -Raw | Invoke-Expression

Get-Process POWERPNT -ErrorAction SilentlyContinue | ForEach-Object { "leftover id=$($_.Id) title='$($_.MainWindowTitle)'"; $_ | Stop-Process -Force }
Start-Sleep -Seconds 3
"--- retry warm launch with longer settle ---"
$proc = Start-Process "POWERPNT.EXE" -PassThru
for($i=0;$i -lt 8;$i++){
  Start-Sleep -Seconds 1
  $a = Get-Process -Id $proc.Id -ErrorAction SilentlyContinue
  if(-not $a){ "exited at t=$i s"; break }
  if($i -eq 7){ "ALIVE after 8s id=$($a.Id) title='$($a.MainWindowTitle)'" }
}
